import styled from 'styled-components'

export const Background = styled.div`
  position: fixed;
  width: 100vw;
  min-height: 100vh;
  background-color: #AAA;
  display: flex;
  justify-content: center;
  margin: 0;
`

export const Wrapper = styled.div`
    position: relative;    
    margin: 0 5px;
    width: 100%;
    max-width: 1400px;
    min-height: 100vh;
    background-color: green;
`

